def gen(rng, size):
    n = rng.randint(2, 100)
    m = max(1, min(size, 100))
    rounds = [rng.randint(1, n)]
    for _ in range(m):
        nxt = rng.randint(1, n)
        while nxt == rounds[-1]:
            nxt = rng.randint(1, n)
        rounds.append(nxt)
    return [n, rounds]

