class Solution:
    def mostVisited(self, n, rounds):
        counts = [0] * (n + 1)
        counts[rounds[0]] += 1
        for i in range(1, len(rounds)):
            cur = rounds[i - 1]
            end = rounds[i]
            while cur != end:
                cur = cur % n + 1
                counts[cur] += 1
        top = max(counts[1:n + 1])
        return [sector for sector in range(1, n + 1) if counts[sector] == top]

