var mostVisited = function(n, rounds) {
    const start = rounds[0];
    const end = rounds[rounds.length - 1];
    const res = [];
    if (start <= end) {
        for (let i = start; i <= end; i++) res.push(i);
    } else {
        for (let i = 1; i <= end; i++) res.push(i);
        for (let i = start; i <= n; i++) res.push(i);
    }
    return res;
};
